parameters.jsonBody:
={
  "model": "claude-sonnet-4-6",
  "max_tokens": 2000,
  "system": "You are a social media content creator for CoachMentor — an AI-powered football coaching education app for grassroots coaches in England (primarily FA Level 1/2, working with U7–U16 age groups). Brand voice: knowledgeable but peer-to-peer, encouraging, passionate about grassroots football. You are a fellow coach who loves the game.

CRITICAL: ALL content must be 100% original. Never reproduce FA session plans, UEFA coaching materials, or any licensed coaching frameworks. Create original drills, tips, and coaching questions only.

Return ONLY valid JSON, no markdown or extra text.",
  "messages": [{
    "role": "user",
    "content": "Generate CoachMentor's weekly social media content plan for week commencing {{ $json.weekCommencing }}.

Current coaching news/trends:
{{ $json.coachingResults }}

Verwood FC context:
{{ $json.verwoodResults }}

Generate this full week plan as JSON with this exact structure:
{
  "weekTheme": "string — overarching coaching theme for the week",
  "tiktok": [
    {"day": "Tuesday", "hook": "first 3 seconds", "body": "10-35 second script", "cta": "final 5 seconds", "caption": "caption + hashtags", "originality": 0.0},
    {"day": "Thursday", ...},
    {"day": "Saturday", ...}
  ],
  "youtube_shorts": [
    {"day": "Wednesday", "title": "...", "script": "...", "description": "...", "tags": [], "originality": 0.0},
    {"day": "Friday", ...},
    {"day": "Sunday", ...}
  ],
  "instagram": [
    {"day": "Monday", "type": "reel|carousel|post", "caption": "...", "slides": [], "hashtags": [], "originality": 0.0},
    {"day": "Wednesday", ...},
    {"day": "Friday", ...}
  ],
  "x_threads": [
    {"day": "Monday", "tweets": ["tweet 1", "tweet 2", "tweet 3"], "originality": 0.0},
    {"day": "Thursday", ...},
    {"day": "Sunday", "type": "coaching_question", "tweets": [...], "originality": 0.0}
  ],
  "overallConfidence": 0.0
}"
  }]
}

={
  "channel": "{{ $env.SLACK_CHANNEL_COACH_REVIEW }}",
  "text": "⚠️ CoachMentor content needs review — originality score {{ $json.overallConfidence }} (below 0.80 threshold)",
  "blocks": [
    {
      "type": "section",
      "text": {
        "type": "mrkdwn",
        "text": "*CoachMentor Weekly Plan — Review Required*\nWeek theme: *{{ $json.weekTheme }}*\nOriginality score: *{{ $json.overallConfidence }}* (below 0.80 threshold)\n\nOne or more content items may be too close to FA/UEFA licensed material. Please review and approve or regenerate."
      }
    },
    {
      "type": "actions",
      "elements": [
        { "type": "button", "text": { "type": "plain_text", "text": "✅ Approve" }, "style": "primary", "action_id": "approve_cm_content" },
        { "type": "button", "text": { "type": "plain_text", "text": "🔄 Regenerate" }, "style": "danger", "action_id": "regen_cm_content" }
      ]
    }
  ]
}

={
  "snippet": {
    "title": "{{ $json.contentPlan.youtube_shorts[0].title }}",
    "description": "{{ $json.contentPlan.youtube_shorts[0].description }}\n\n🎯 Try CoachMentor FREE for 7 days: https://coachmentor.co.uk/trial\n\n#GrassrootsFootball #FootballCoaching #CoachingTips #FACoach #YouthFootball",
    "tags": {{ JSON.stringify($json.contentPlan.youtube_shorts[0].tags) }},
    "categoryId": "17",
    "defaultLanguage": "en-GB"
  },
  "status": {
    "privacyStatus": "public",
    "selfDeclaredMadeForKids": false,
    "publishAt": "{{ $now.startOf('week').plus({days: 2}).set({hour: 8}).toISO() }}"
  }
}

={
  "model": "claude-sonnet-4-6",
  "max_tokens": 400,
  "system": "Classify social media engagement for CoachMentor, a football coaching app. Determine the likely intent of commenters based on comment text. Return JSON only.",
  "messages": [{
    "role": "user",
    "content": "Classify this social media engagement for CoachMentor (football coaching app).\n\nPost caption: {{ $json.caption || $json.title }}\nEngagement stats: {{ $json.view_count || $json.reach }} views, {{ $json.comment_count }} comments\n\nReturn JSON: {\"intent\": \"coach|parent|player|unknown\", \"confidence\": 0.0, \"dm_recommended\": true|false, \"dm_angle\": \"suggested approach for DM\"}"
  }]
}

={
  "model": "claude-sonnet-4-6",
  "max_tokens": 200,
  "system": "Write a friendly, natural DM for CoachMentor — a football coaching app. Sound like a fellow coach, not a brand. Max 3 sentences. Never use exclamation marks more than once. Offer a 7-day free trial naturally.",
  "messages": [{
    "role": "user",
    "content": "Write a short DM to send to a grassroots football coach who engaged with our content.

Content they engaged with: {{ $json.caption || $json.title }}
Angle: {{ JSON.parse($('B05 — Claude: Classify Intent').item.json.content[0].text).dm_angle }}

The DM should:
1. Reference what they engaged with naturally
2. Offer a 7-day free trial of CoachMentor
3. Include link: coachmentor.co.uk/trial

Return plain text DM only. No quotes. Max 280 characters."
  }]
}

={
  "model": "claude-sonnet-4-6",
  "max_tokens": 1200,
  "system": "You are a social media content creator for CoachMentor, a grassroots football coaching app. Create match-week reactive content. All content must be 100% original — never reproduce FA session plans or licensed materials. Return JSON only.",
  "messages": [{
    "role": "user",
    "content": "Generate match-day weekend content for CoachMentor.

Verwood FC context: {{ $json.web?.results?.[0]?.description || 'Weekend fixture upcoming' }}

Generate: {
  "saturday_tiktok": {"time": "07:30", "hook": "...", "body": "...", "cta": "...", "originality": 0.0},
  "saturday_x": {"time": "08:00", "tweets": ["tweet1", "tweet2", "tweet3"], "originality": 0.0},
  "saturday_ig_story": {"time": "09:00", "text": "coaching question sticker text", "originality": 0.0},
  "sunday_x_thread": {"time": "18:00", "type": "coaching_question", "tweets": ["question tweet", "context tweet", "cta tweet"], "originality": 0.0}
}"
  }]
}
